import Typewriter from "typewriter-effect"
import styled from "styled-components"

import { InView, useInView } from 'react-intersection-observer';

const Projects = ({ id }) => {
  return (
    <ProjectsContainer id={id}>
              {/* <Typewriter
                onInit={(typewriter) => {
                  typewriter
                    .changeDelay(80)
                    .typeString("Projects")
                    .pauseFor(1000)
                    .callFunction(state => state.elements.cursor.style.display = "none")
                    .start()
                }}
              /> */}

  <InView>
    {({ inView, ref, entry }) => (
      <div ref={ref}>
        {inView && "inView"}
        {inView &&
          <Typewriter
            onInit={(typewriter) => {
              typewriter
                .changeDelay(80)
                .typeString("Projects")
                .pauseFor(1000)
                .callFunction(state => state.elements.cursor.style.display = "none")
                .start()
          }}/>
        }
      </div>
    )}
  </InView>

    </ProjectsContainer>
  )
}

const ProjectsContainer = styled.section`
  width: 100%;
  height: 100vh;

  margin-top: 50em;

  color: white;
  font-size: 3em;
`

export default Projects
